// AnaSayfa.js
import React, { useEffect, useMemo, useState } from "react";
import { motion } from "framer-motion";
import {
    Card,
    CardHeader,
    CardContent,
    CardTitle,
    CardDescription,
} from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Tabs, TabsList, TabsTrigger, TabsContent } from "@/components/ui/tabs";
import { Badge } from "@/components/ui/badge";
import { Progress } from "@/components/ui/progress";
import { Input } from "@/components/ui/input";
import {
    Truck,
    Package,
    MapPin,
    Clock,
    ArrowUpRight,
    ArrowDownRight,
    Bell,
    Search,
    Filter,
} from "lucide-react";
import {
    ResponsiveContainer,
    AreaChart,
    Area,
    Tooltip,
    XAxis,
    YAxis,
    CartesianGrid,
    BarChart,
    Bar,
} from "recharts";
import { createClient } from "@supabase/supabase-js";

// Supabase client — projede global client yoksa buradan kullanabilirsiniz
const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL;
const supabaseAnonKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY;
const supabase = createClient(supabaseUrl, supabaseAnonKey);

// Fallback veriler (JSON gelmezse)
const DEFAULT_HACIM = [
    { ad: "Pzt", sevk: 120, teslim: 92 },
    { ad: "Sal", sevk: 150, teslim: 110 },
    { ad: "Çar", sevk: 130, teslim: 108 },
    { ad: "Per", sevk: 180, teslim: 150 },
    { ad: "Cum", sevk: 210, teslim: 170 },
    { ad: "Cmt", sevk: 160, teslim: 140 },
    { ad: "Paz", sevk: 140, teslim: 120 },
];

const DEFAULT_FILO = [
    { ay: "Ocak", doluluk: 62 },
    { ay: "Şubat", doluluk: 68 },
    { ay: "Mart", doluluk: 74 },
    { ay: "Nisan", doluluk: 71 },
    { ay: "Mayıs", doluluk: 79 },
    { ay: "Haz", doluluk: 83 },
    { ay: "Tem", doluluk: 88 },
];

const DEFAULT_GONDERILER = [
    {
        id: "TRK-7841",
        musteri: "Nova Market",
        cikis: "İstanbul",
        varis: "Ankara",
        tahmini: "Bugün 16:30",
        durum: "Yolda",
    },
    {
        id: "TRK-7833",
        musteri: "Atlas E-Ticaret",
        cikis: "Kocaeli",
        varis: "İzmir",
        tahmini: "Yarın 10:00",
        durum: "Gecikme",
    },
    {
        id: "TRK-7819",
        musteri: "Mavi Tekstil",
        cikis: "Bursa",
        varis: "Edirne",
        tahmini: "Teslim edildi",
        durum: "Teslim",
    },
    {
        id: "TRK-7802",
        musteri: "Bio Farma",
        cikis: "İstanbul",
        varis: "Eskişehir",
        tahmini: "Bugün 18:00",
        durum: "Yolda",
    },
];

const DurumEtiketi = ({ durum }) => {
    const renk =
        durum === "Teslim"
            ? "bg-emerald-500/20 text-emerald-300 border-emerald-500/30"
            : durum === "Gecikme"
                ? "bg-rose-500/20 text-rose-300 border-rose-500/30"
                : "bg-blue-500/20 text-blue-300 border-blue-500/30";
    const icerik =
        durum === "Teslim" ? "Teslim Edildi" : durum === "Gecikme" ? "Gecikme" : "Yolda";
    return <Badge className={`rounded-full border ${renk}`}>{icerik}</Badge>;
};

// ... (kalan AnaSayfa bileşeni supabase fetch + UI aynı şekilde devam ediyor)
